const Home = () => {
  return (
    <div className="text-center p-10">
      <h1 className="text-4xl font-bold mb-4">Welcome to Cloud Kitchen</h1>
      <p className="text-lg">Your favorite pickles, delivered to your door!</p>
    </div>
  );
};

export default Home;
